// ============================================================
// CONSOLIDA OS 314 REGISTROS EM CONTEXTO PARA O AI AGENT
// Calcula resumos, rankings e tendências automaticamente
// ============================================================

const registros = $input.all().map(i => i.json);

if (!registros || registros.length === 0) {
  return [{ json: { contexto: 'Nenhum dado encontrado na planilha.', pergunta: $('Edit Fields').item.json.mensagem, nome: $('Edit Fields').item.json.pushName } }];
}

const fmtBRL = v => Number(v || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
const hoje = new Date().toLocaleDateString('pt-BR');

// ── Totais gerais ──
const totalVendas = registros.reduce((s, r) => s + Number(r.valor_total || 0), 0);
const totalPedidos = registros.length;
const ticketMedio = totalPedidos > 0 ? totalVendas / totalPedidos : 0;

// ── Ranking por vendedor ──
const porVendedor = {};
registros.forEach(r => {
  const v = r.vendedor || 'Desconhecido';
  if (!porVendedor[v]) porVendedor[v] = { total: 0, pedidos: 0 };
  porVendedor[v].total += Number(r.valor_total || 0);
  porVendedor[v].pedidos += 1;
});
const rankingVendedores = Object.entries(porVendedor)
  .sort((a, b) => b[1].total - a[1].total)
  .map(([nome, d], i) => ({
    posicao: i + 1,
    vendedor: nome,
    total_vendas: fmtBRL(d.total),
    total_pedidos: d.pedidos,
    ticket_medio: fmtBRL(d.total / d.pedidos)
  }));

// ── Ranking por produto ──
const porProduto = {};
registros.forEach(r => {
  const p = r.produto || 'Desconhecido';
  if (!porProduto[p]) porProduto[p] = { total: 0, pedidos: 0, quantidade: 0 };
  porProduto[p].total += Number(r.valor_total || 0);
  porProduto[p].pedidos += 1;
  porProduto[p].quantidade += Number(r.quantidade || 0);
});
const rankingProdutos = Object.entries(porProduto)
  .sort((a, b) => b[1].total - a[1].total)
  .map(([nome, d], i) => ({
    posicao: i + 1,
    produto: nome,
    total_vendas: fmtBRL(d.total),
    total_pedidos: d.pedidos,
    quantidade_vendida: d.quantidade
  }));

// ── Ranking por canal ──
const porCanal = {};
registros.forEach(r => {
  const c = r.canal || 'Desconhecido';
  if (!porCanal[c]) porCanal[c] = { total: 0, pedidos: 0 };
  porCanal[c].total += Number(r.valor_total || 0);
  porCanal[c].pedidos += 1;
});
const rankingCanais = Object.entries(porCanal)
  .sort((a, b) => b[1].total - a[1].total)
  .map(([canal, d]) => ({
    canal,
    total_vendas: fmtBRL(d.total),
    total_pedidos: d.pedidos
  }));

// ── Ranking por cidade ──
const porCidade = {};
registros.forEach(r => {
  const c = r.cidade || r.client_cidade || 'Desconhecida';
  if (!porCidade[c]) porCidade[c] = { total: 0, pedidos: 0 };
  porCidade[c].total += Number(r.valor_total || 0);
  porCidade[c].pedidos += 1;
});
const rankingCidades = Object.entries(porCidade)
  .sort((a, b) => b[1].total - a[1].total)
  .map(([cidade, d]) => ({
    cidade,
    total_vendas: fmtBRL(d.total),
    total_pedidos: d.pedidos
  }));

// ── Monta contexto final ──
const contexto = {
  data_consulta: hoje,
  total_registros: totalPedidos,
  resumo_geral: {
    total_pedidos: totalPedidos,
    total_vendas: fmtBRL(totalVendas),
    ticket_medio: fmtBRL(ticketMedio)
  },
  ranking_vendedores: rankingVendedores,
  ranking_produtos: rankingProdutos,
  ranking_canais: rankingCanais,
  ranking_cidades: rankingCidades
};

return [{
  json: {
    contexto: JSON.stringify(contexto, null, 2),
    pergunta: $('Edit Fields').item.json.mensagem,
    nome: $('Edit Fields').item.json.pushName || 'usuário'
  }
}];
